def pivotArray(self, nums: List[int], pivot: int) -> List[int]:
    left, right = 0, len(nums) - 1
    while left < right:
        if nums[left] <= pivot:
            left += 1
        elif nums[right] >= pivot:
            right -= 1
        else:
            nums[left], nums[right] = nums[right], nums[left]
    return nums

